using System.Reflection.PortableExecutable;

var path = "/home/runner/.nuget/packages/xunit.v3.extensibility.core/1.1.0/lib/netstandard2.0/xunit.v3.core.dll";
using var fs = new System.IO.FileStream(path, System.IO.FileMode.Open, System.IO.FileAccess.Read);
using var pe = new PEReader(fs);
var reader = pe.GetMetadataReader();

foreach(var tdh in reader.TypeDefinitions) {
    var td = reader.GetTypeDefinition(tdh);
    var name = reader.GetString(td.Name);
    if (name == "FactAttribute" || name == "TheoryAttribute") {
        var ns = reader.GetString(td.Namespace);
        Console.WriteLine($"{ns}.{name}");
        foreach(var mh in td.GetMethods()) {
            var md = reader.GetMethodDefinition(mh);
            var mname = reader.GetString(md.Name);
            if (mname == ".ctor") {
                var sig = md.DecodeSignature(new SignatureTypeProvider(), null);
                var parms = string.Join(", ", sig.ParameterTypes);
                Console.WriteLine($"  .ctor({parms})");
            }
        }
    }
}

class SignatureTypeProvider : ISignatureTypeProvider<string, object?> {
    public string GetPrimitiveType(PrimitiveTypeCode typeCode) => typeCode.ToString();
    public string GetTypeFromDefinition(MetadataReader r, TypeDefinitionHandle h, byte raw) { var td = r.GetTypeDefinition(h); return r.GetString(td.Name); }
    public string GetTypeFromReference(MetadataReader r, TypeReferenceHandle h, byte raw) { var tr = r.GetTypeReference(h); return r.GetString(tr.Name); }
    public string GetSZArrayType(string t) => t + "[]";
    public string GetGenericInstantiation(string t, System.Collections.Immutable.ImmutableArray<string> args) => $"{t}<{string.Join(",",args)}>";
    public string GetArrayType(string t, ArrayShape s) => t + "[]";
    public string GetByReferenceType(string t) => "ref " + t;
    public string GetPointerType(string t) => t + "*";
    public string GetPinnedType(string t) => t;
    public string GetGenericMethodParameter(object? c, int i) => $"T{i}";
    public string GetGenericTypeParameter(object? c, int i) => $"T{i}";
    public string GetModifiedType(string modifier, string t, bool isRequired) => t;
    public string GetFunctionPointerType(MethodSignature<string> s) => "fnptr";
    public string GetTypeFromSpecification(MetadataReader r, object? c, TypeSpecificationHandle h, byte raw) => "spec";
}
